PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT(SUM(?games) AS ?total) WHERE {
  VALUES ?year {
    1977 1978 2008 2009
  }
  ?event wdt:P585 ?date .
  FILTER(year(?date) = ?year)
  ?event wdt:P253 wd:Q334634 .
  ?event wdt:P255 wd:Q650840 .
  ?event wdt:P1798 ?games .
}

